file.content:
.profile-page-loading-container{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-backdrop-heavy);
    backdrop-filter: blur(25px);
    width: 100%;
    height:100vh;
    z-index: 3;
}
.profile-bg-picker-container{
    position: absolute;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    width: 400px;
    height: 400px;
    background-color: var(--bg-elevated);
    z-index: 4;
    padding: 1.25rem;
    border-radius: 18px;
    box-shadow: 0 12px 48px rgba(0, 0, 0, 0.12), 0 0 0 1px var(--border-light);
    gap: 1rem;
    color: var(--text-primary);
}
.profile-bg-picker-header{
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 600;
    font-size: 0.95rem;
    color: var(--text-heading);
}
.profile-bg-color-palette{
    display: flex;
    justify-content: space-evenly;
    width: 100%;
    height: 50px;
    padding: 1rem 0rem;
    border: 1px solid var(--border-light);
    border-radius: 10px;
}
.gradient-box{
    width: 50px;
    height: 50px;
    border-radius: 10px;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    transform: scale(1) rotate(0deg);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}
.gradient-box:hover{
    transform: scale(1.08) rotate(1.5deg);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.18);
}
.gradient-box:active{
    transform: scale(0.97);
}
.profile-bg-preview{
    position: relative;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    width: 100%;
    height: 50%;
    border-radius: 10px;
    gap: 1rem;
}
.controls{
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    padding: 0.5rem;
    border-radius: 10px;
    background-color: var(--bg-elevated);
    position: relative;
    z-index: 10;
    margin-bottom: 0.2rem;
}

.remove-bg-preview{
    position: absolute;
    bottom: 80%;
    left: 85%;
    display: flex;
    justify-content: center;
    align-items: center;
    width: fit-content;
    height: fit-content;
    padding: 0.2rem;
    background-color: var(--bg-backdrop-heavy);
    z-index: 10;
    margin-bottom: 0.2rem;
    border-radius: 50%;
    cursor: pointer;
}
.remove-bg-preview:hover{
    background-color: var(--bg-elevated);
}
.add-bgImage-bttn{
    position: absolute;
    bottom: 65px;
    width: 50px;
    height: 50px;
    border-radius: 10px;
    cursor: pointer;
    transition: ease-in-out 0.1s;
    transform: scale(1);
}
.add-bgImage-bttn:hover{
    transform: scale(1.1);
}

.canvel-save-container{
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    height: fit-content;
}
.cancel-button{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.8rem;
    background-color: var(--bg-hover);
    color: var(--text-primary);
    border-radius: 10px;
    cursor: pointer;
    transition: background-color 0.2s ease, transform 0.15s ease;
    font-weight: 600;
    font-size: 0.82rem;
}
.save-button{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.8rem;
    background-color: var(--accent-dark);
    color: var(--bg-primary);
    border-radius: 10px;
    cursor: pointer;
    transition: background-color 0.2s ease, transform 0.15s ease, box-shadow 0.2s ease;
    font-weight: 600;
    font-size: 0.82rem;
}
.save-button:hover{
   background-color: var(--accent-dark-hover);
   transform: translateY(-1px);
   box-shadow: 0 3px 12px rgba(0, 0, 0, 0.1);
}
.save-button:active{
   transform: translateY(0);
   box-shadow: none;
}
.cancel-button:hover{
   background-color: var(--bg-secondary);
}
.cancel-button:active{
   transform: scale(0.97);
}


.blurred-img-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(40px) saturate(1.2);
    transform: scale(1.4);
    animation: bgFadeIn 0.6s ease-out;
}
.blurred-gradient-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(100px) saturate(1.1);
    transform: scale(1.4);
    opacity: 0.1;
    animation: bgFadeIn 0.8s ease-out;
}
@keyframes bgFadeIn{
    from{ opacity: 0; transform: scale(1.5); }
    to{ opacity: 1; transform: scale(1.4); }
}
.profile-parent-container{
    position: relative;
    display: flex;
    justify-content: flex-start;
    align-items: center;
    width: 100%;
    height: 100vh;
    overflow-y: hidden;
    overflow-x: hidden;
}
.profile-center-bar-container{
    position: relative;
    left: 250px;
    display: flex;
    flex-direction: column;
    align-items: center;
    width: 750px;
    height: 100vh;
    overflow-y: auto;
}
.profile-center-bar-container::-webkit-scrollbar{
    display: none;
}
.profile-sidebar-right-holder-container{
    position: fixed;
    left: 1000px;
    display: flex;
    width: 25%;
    height: 100%;
    border-left: 0.7px solid var(--border-light);
}
.hero-section{
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    justify-content: flex-start;
    width: 90%;
    padding: 1.4rem 1.4rem 1.2rem 1.4rem;
    margin-top: 1rem;
    border-radius: 20px;
    gap: 0.8rem;
    border: 0.7px solid var(--border-light);
    transition: box-shadow 0.35s ease, border-color 0.35s ease;
}
.hero-section:hover{
    box-shadow: 0 8px 32px rgba(0, 0, 0, 0.06), 0 2px 8px rgba(0, 0, 0, 0.04);
    border-color: var(--bg-glass-border);
}
.profile-top-row{
    display: flex;
    align-items: center;
    justify-content: space-between;
    width: 100%;
}
.profile-avatar-ring{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 5px;
    border-radius: 50%;
    border: 2px dashed currentColor;
    opacity: 0.9;
    position: relative;
}
.profile-avatar-ring.badge-ring-legend{
    border: 3px solid #FFD700;
    box-shadow:
        0 0 10px 3px rgba(255, 215, 0, 0.5),
        0 0 20px 6px rgba(255, 215, 0, 0.35),
        0 0 35px 10px rgba(255, 215, 0, 0.2),
        inset 0 0 12px rgba(255, 215, 0, 0.15);
    opacity: 1;
    animation: glow-legend-profile 2s ease-in-out infinite alternate;
}
.profile-avatar-ring.badge-ring-og{
    border: 3px solid #9B59FF;
    box-shadow:
        0 0 10px 3px rgba(155, 89, 255, 0.5),
        0 0 20px 6px rgba(155, 89, 255, 0.35),
        0 0 35px 10px rgba(155, 89, 255, 0.2),
        inset 0 0 12px rgba(155, 89, 255, 0.15);
    opacity: 1;
    animation: glow-og-profile 2s ease-in-out infinite alternate;
}

@keyframes glow-legend-profile {
    from {
        box-shadow:
            0 0 10px 3px rgba(255, 215, 0, 0.5),
            0 0 20px 6px rgba(255, 215, 0, 0.35),
            0 0 35px 10px rgba(255, 215, 0, 0.2),
            inset 0 0 12px rgba(255, 215, 0, 0.15);
    }
    to {
        box-shadow:
            0 0 14px 5px rgba(255, 215, 0, 0.6),
            0 0 28px 10px rgba(255, 215, 0, 0.4),
            0 0 45px 15px rgba(255, 215, 0, 0.25),
            inset 0 0 16px rgba(255, 215, 0, 0.2);
    }
}

@keyframes glow-og-profile {
    from {
        box-shadow:
            0 0 10px 3px rgba(155, 89, 255, 0.5),
            0 0 20px 6px rgba(155, 89, 255, 0.35),
            0 0 35px 10px rgba(155, 89, 255, 0.2),
            inset 0 0 12px rgba(155, 89, 255, 0.15);
    }
    to {
        box-shadow:
            0 0 14px 5px rgba(155, 89, 255, 0.6),
            0 0 28px 10px rgba(155, 89, 255, 0.4),
            0 0 45px 15px rgba(155, 89, 255, 0.25),
            inset 0 0 16px rgba(155, 89, 255, 0.2);
    }
}
.my-profile-image{
    position: relative;
    border-radius: 50%;
    object-fit: cover;
    width: 120px;
    height: 120px;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.profile-avatar-ring:hover .my-profile-image{
    transform: scale(1.04);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12);
}
.profile-stats-container{
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: 0.15rem;
    padding: 0.5rem 0.75rem;
    border-radius: 14px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 0.5px solid var(--bg-glass-border);
    transition: background-color 0.25s ease, box-shadow 0.25s ease;
}
.profile-stats-container:hover{
    background-color: var(--bg-glass-border);
    box-shadow: 0 2px 12px rgba(0, 0, 0, 0.05);
}
.profile-stat-item{
    display: flex;
    align-items: baseline;
    gap: 0.4rem;
}
.stat-number{
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.5rem;
    font-weight: 700;
    letter-spacing: -0.02em;
}
.stat-label{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    opacity: 0.65;
}
.profile-actions-row{
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: fit-content;
    padding: 0.5rem 0.75rem;
    border-radius: 14px;
    background-color: var(--bg-glass);
    backdrop-filter: blur(25px);
    -webkit-backdrop-filter: blur(25px);
    border: 0.5px solid var(--bg-glass-border);
    transition: background-color 0.25s ease;
}
.profile-actions-row:hover{
    background-color: var(--bg-glass-border);
}
.edit-profile-bttn{
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.35rem;
    padding: 0.5rem 1.2rem;
    border-radius: 25px;
    background-color: transparent;
    color: inherit;
    border: 1.5px solid currentColor;
    cursor: pointer;
    user-select: none;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 500;
    font-size: 0.82rem;
    transition: background-color 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease, opacity 0.2s ease;
    opacity: 0.85;
}
.edit-profile-bttn:hover{
    background-color: var(--bg-glass);
    opacity: 1;
    transform: translateY(-1px);
    box-shadow: 0 3px 12px rgba(0, 0, 0, 0.08);
}
.edit-profile-bttn:active{
    transform: translateY(0);
    box-shadow: none;
}
.font-selector-container{
    position: absolute;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    width: 200px;
    height: 120px;
    background-color: var(--bg-elevated);
    z-index: 5;
    padding: 1rem;
    border-radius: 16px;
    box-shadow: 0 12px 48px rgba(0, 0, 0, 0.12), 0 0 0 1px var(--border-light);
    gap: 1rem;
    color: var(--text-primary);
}
.save-font-color-bttn-container{
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    height: fit-content;
}
.input-color{
    border: none;
    cursor: pointer;
    border-radius: 50%;
    width: 50px;
    height: 50px;
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);
}
.font-picker-container{
    display: flex;
    justify-content: center;
    align-items: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    background-color: transparent;
    border: 1.5px solid currentColor;
    cursor: pointer;
    user-select: none;
    transition: background-color 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease, opacity 0.2s ease;
    opacity: 0.85;
}
.font-picker-container:hover{
    background-color: var(--bg-glass);
    opacity: 1;
    transform: translateY(-1px);
    box-shadow: 0 3px 12px rgba(0, 0, 0, 0.08);
}
.font-picker-container:active{
    transform: translateY(0);
    box-shadow: none;
}
.layout-picker-container{
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 0.9rem;
    border-radius: 25px;
    background-color: transparent;
    border: 1.5px solid currentColor;
    cursor: pointer;
    user-select: none;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 500;
    font-size: 0.82rem;
    transition: background-color 0.2s ease, opacity 0.2s ease, transform 0.2s ease, box-shadow 0.2s ease;
    opacity: 0.85;
}
.layout-picker-container:hover{
    background-color: var(--bg-glass);
    opacity: 1;
    transform: translateY(-1px);
    box-shadow: 0 3px 12px rgba(0, 0, 0, 0.08);
}
.layout-picker-container:active{
    transform: translateY(0);
    box-shadow: none;
}
.layout-picker-container.is-active{
    background-color: var(--bg-glass);
    border-color: var(--accent-dark);
    opacity: 1;
}
.profile-layout-builder-bg{
    position: absolute;
    inset: 0;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-backdrop);
    backdrop-filter: blur(5px);
    -webkit-backdrop-filter: blur(5px);
    z-index: 140;
}
.profile-layout-builder-container{
    display: flex;
    flex-direction: column;
    width: min(92vw, 380px);
    border-radius: 18px;
    background-color: var(--bg-elevated);
    padding: 1rem;
    gap: 0.8rem;
    box-shadow: var(--shadow-modal);
    color: var(--text-primary);
}
.profile-layout-builder-header{
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}
.profile-layout-builder-title{
    margin: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1rem;
    font-weight: 700;
}
.profile-layout-builder-subtitle{
    margin: 0;
    font-family: var(--font-ui);
    font-size: 0.78rem;
    color: var(--text-muted);
}
.profile-layout-builder-list{
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}
.profile-stats-container.profile-section-size-sm{
    padding: 0.35rem 0.5rem;
}
.profile-stats-container.profile-section-size-sm .stat-number{
    font-size: 1.2rem;
}
.profile-stats-container.profile-section-size-sm .stat-label{
    font-size: 0.72rem;
}
.profile-stats-container.profile-section-size-lg{
    padding: 0.55rem 0.8rem;
}
.profile-stats-container.profile-section-size-lg .stat-number{
    font-size: 1.75rem;
}
.profile-stats-container.profile-section-size-lg .stat-label{
    font-size: 0.9rem;
}
.profile-bio-container.profile-section-size-sm{
    padding: 0.3rem 0.45rem;
}
.profile-bio-container.profile-section-size-sm .profile-bio{
    font-size: 0.78rem;
}
.profile-bio-container.profile-section-size-lg{
