    padding: 0;
    font-family: "Lexend Deca", sans-serif;
    font-size: 1.75rem;
    font-weight: 700;
    line-height: 1.1;
    letter-spacing: -0.02em;
}
.profile-media-count{
    font-family: var(--font-ui);
    font-size: 1.2rem;
    font-weight: 600;
    opacity: 0.7;
}
.profile-media-warning{
