    width: 100%;
    max-height: 92vh;
    object-fit: contain;
    display: block;
}
.profile-media-lightbox-close{
    position: absolute;
    top: 0.55rem;
    right: 0.55rem;
    z-index: 2;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 34px;
    height: 34px;
    border: none;
    border-radius: 50%;
