        font-size: 1.2rem;
    }
    .profile-name {
        font-size: 1.35rem;
    }
    .profile-media-section{
        padding: 0.7rem;
    }
    .profile-media-heading{
        font-size: 1.35rem;
    }
    .profile-media-count{
        font-size: 0.95rem;
    }
    .profile-editor-bg {
        position: absolute;
        display: flex;
        justify-content: center;
        align-items: center;
        background-color: var(--bg-backdrop);
        backdrop-filter: blur(5px);
        -webkit-backdrop-filter: blur(5px);
        width: 100%;
        height: 100vh;
        z-index: 135;
    }

    .profile-editor-container {
        display: flex;
        flex-direction: column;
        width: 90%;
        height: fit-content;
        border-radius: 15px;
        background-color: var(--bg-elevated);
        padding: 1rem;
        gap: 1rem;
    }
    .profile-edit-image-bg {
        display: flex;
        justify-content: center;
        align-items: center;
        position: absolute;
        width: 100px;
        height: 100px;
        background-color: rgba(120, 120, 120, 0.588);
        z-index: 2;
        border-radius: 50%;
        cursor: pointer;
    }
    .my-profile-image-editable {
        position: relative;
        border-radius: 50%;
        object-fit: cover;
        width: 100px;
        height: 100px;
    }
    .profile-bg-picker-container {
        position: absolute;
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        width: 380px;
        height: 400px;
        background-color: var(--bg-elevated);
        z-index: 136;
        padding: 1rem;
        border-radius: 20px;
        box-shadow: var(--shadow-modal);
        gap: 1rem;
        color: var(--text-primary);
    }
}

@media (max-width: 480px){
    .profile-parent-container {
        position: relative;
        flex-direction: column;
        display: flex;
        justify-content: flex-end;
        align-items: center;
        width: 100%;
        height: 100vh;
        overflow-y: hidden;
        overflow-x: hidden;
    }
    .profile-sidebar-right-holder-container {
        display: none;
    }

    .profile-center-bar-container {
        position: absolute;
        left: 1px;
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: center;
        width: 100%;
        height: 100vh;
    }
    .my-profile-image {
        width: 90px;
        height: 90px;
    }
    .stat-number {
        font-size: 1.2rem;
    }
    .profile-name {
        font-size: 1.35rem;
    }
    .profile-media-section{
        padding: 0.7rem;
    }
    .profile-media-heading{
        font-size: 1.35rem;
    }
    .profile-media-count{
        font-size: 0.95rem;
    }
    .profile-editor-bg {
        position: absolute;
        display: flex;
        justify-content: center;
        align-items: center;
        background-color: var(--bg-backdrop);
        backdrop-filter: blur(5px);
        -webkit-backdrop-filter: blur(5px);
        width: 100%;
        height: 100vh;
        z-index: 135;
    }

    .profile-editor-container {
        display: flex;
        flex-direction: column;
        width: 90%;
        height: fit-content;
        border-radius: 15px;
        background-color: var(--bg-elevated);
        padding: 1rem;
        gap: 1rem;
    }
    .profile-edit-image-bg {
        display: flex;
        justify-content: center;
        align-items: center;
        position: absolute;
        width: 100px;
        height: 100px;
        background-color: rgba(120, 120, 120, 0.588);
        z-index: 2;
        border-radius: 50%;
        cursor: pointer;
    }
    .my-profile-image-editable {
        position: relative;
        border-radius: 50%;
        object-fit: cover;
        width: 100px;
        height: 100px;
    }
    .profile-bg-picker-container {
        position: absolute;
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        width: 380px;
        height: 400px;
        background-color: var(--bg-elevated);
        padding: 1rem;
        border-radius: 20px;
        box-shadow: var(--shadow-modal);
        gap: 1rem;
        z-index: 136;
        color: var(--text-primary);
    }
}

