.profile-page-loading-container{
    position: absolute;
    display: flex;
    justify-content: center;
    align-items: center;
    background-color: var(--bg-backdrop-heavy);
    backdrop-filter: blur(25px);
    width: 100%;
    height:100vh;
    z-index: 3;
}
.profile-bg-picker-container{
    position: absolute;
    display: flex;
    flex-direction: column;
    justify-content: flex-start;
    align-items: flex-start;
    width: 400px;
    height: 400px;
    background-color: var(--bg-elevated);
    z-index: 4;
    padding: 1.25rem;
    border-radius: 18px;
    box-shadow: 0 12px 48px rgba(0, 0, 0, 0.12), 0 0 0 1px var(--border-light);
    gap: 1rem;
    color: var(--text-primary);
}
.profile-bg-picker-header{
    display: flex;
    justify-content: flex-start;
    align-items: flex-start;
    font-family: "Lexend Deca", sans-serif;
    font-weight: 600;
    font-size: 0.95rem;
    color: var(--text-heading);
}
.profile-bg-color-palette{
    display: flex;
    justify-content: space-evenly;
    width: 100%;
    height: 50px;
    padding: 1rem 0rem;
    border: 1px solid var(--border-light);
    border-radius: 10px;
}
.gradient-box{
    width: 50px;
    height: 50px;
    border-radius: 10px;
    cursor: pointer;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
    transform: scale(1) rotate(0deg);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
}
.gradient-box:hover{
    transform: scale(1.08) rotate(1.5deg);
    box-shadow: 0 6px 20px rgba(0, 0, 0, 0.18);
}
.gradient-box:active{
    transform: scale(0.97);
}
.profile-bg-preview{
    position: relative;
    display: flex;
    align-items: flex-end;
    justify-content: center;
    width: 100%;
    height: 50%;
    border-radius: 10px;
    gap: 1rem;
}
.controls{
    display: flex;
    justify-content: center;
    align-items: center;
