}


.blurred-img-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(40px) saturate(1.2);
    transform: scale(1.4);
    animation: bgFadeIn 0.6s ease-out;
}
.blurred-gradient-bg{
    position: absolute;
    width: 100%;
    height: 100vh;
    filter: blur(100px) saturate(1.1);
    transform: scale(1.4);
    opacity: 0.1;
    animation: bgFadeIn 0.8s ease-out;
}
@keyframes bgFadeIn{
    from{ opacity: 0; transform: scale(1.5); }
    to{ opacity: 1; transform: scale(1.4); }
}
