    position: relative;
    border-radius: 50%;
    object-fit: cover;
    width: 120px;
    height: 120px;
    transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.profile-avatar-ring:hover .my-profile-image{
    transform: scale(1.04);
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.12);
}
