    letter-spacing: -0.02em;
}
.stat-label{
    font-family: var(--font-ui);
    font-size: 0.8rem;
    font-weight: 500;
    opacity: 0.65;
}
.profile-actions-row{
    display: flex;
    align-items: center;
    gap: 0.5rem;
    width: fit-content;
    padding: 0.5rem 0.75rem;
    border-radius: 14px;
    background-color: var(--bg-glass);
