        width: 100px;
        height: 100px;
        background-color: rgba(120, 120, 120, 0.588);
        z-index: 2;
        border-radius: 50%;
        cursor: pointer;
    }
    .my-profile-image-editable {
        position: relative;
        border-radius: 50%;
        object-fit: cover;
        width: 100px;
        height: 100px;
    }
    .profile-bg-picker-container {
        position: absolute;
        display: flex;
        flex-direction: column;
        justify-content: flex-start;
        align-items: flex-start;
        width: 380px;
        height: 400px;
        background-color: var(--bg-elevated);
        z-index: 136;
        padding: 1rem;
        border-radius: 20px;
        box-shadow: var(--shadow-modal);
        gap: 1rem;
        color: var(--text-primary);
    }
}

